 	{\leavevmode
 		\begin{enumerate}
 			\item For $\mathbf{m}= (1, 1/2, 1/2)$, we have
 			\begin{align*}
 				\underline{ {H}}_{1} = m_1 = 1/2 > 0,\quad\overline{H}_{1} = m_0 - m_1 = 1/2>0,\\
 				\underline{ {H}}_{2} = \begin{vmatrix}
 					m_0 & m_1\\
 					m_1 & m_2
 				\end{vmatrix} = 1/4 >0,\quad\overline{H}_{2} = 
 				m_1 - m_2 = 0.
 			\end{align*}
 			The uniquely determined discrete distribution has only two jumps, one at $0$ and one at $1$. Hence the probability density function (pdf) is $\frac{1}{2} \delta(x) + \frac{1}{2} \delta(x-1)$.
 			\item For $\mathbf{m} = (1, 1/2, 1/3)$, we have
 			\begin{align*}
 				\underline{ {H}}_{1}  = m_1= 1/2 > 0,\quad\overline{H}_{1}= m_0 - m_1= 1/2  >0,\\
 				\underline{ {H}}_{2} = \begin{vmatrix}
 					m_0 & m_1\\
 					m_1 & m_2
 				\end{vmatrix} = 1/12 >0,\quad\overline{H}_{2} = 
 				m_1 - m_2 = 1/6 >0.
 			\end{align*}
 			There are infinitely many solutions since all Hankel determinants are positive, such as $f(x) = 1 $ and $f(x) = \frac{1}{2} \delta\left(x- \left(3+\sqrt{3}\right)/6 \right) + \frac{1}{2} \delta\left(x- \left(3-\sqrt{3}\right)/6 \right) $. 
 		\end{enumerate}
 	}

